const container = document.getElementById('list-container');
const loader = document.getElementById('loader');

let currentPage = 1;
const maxPages = 5;
let isLoading = false;
let itemIndex = 5;

function loadMoreItems() {
  if (isLoading || currentPage >= maxPages) return;
  isLoading = true;
  loader.classList.remove('hidden');
  container.appendChild(loader); // keep loader at the bottom

  setTimeout(() => {
    for (let i = 0; i < 5; i++) {
      itemIndex++;
      const div = document.createElement('div');
      div.className = 'p-3 bg-slate-950/40 rounded border border-slate-700 text-sm';
      div.textContent = `Item #${itemIndex}`;
      container.insertBefore(div, loader);
    }

    currentPage++;
    isLoading = false;
    loader.classList.add('hidden');

    if (currentPage >= maxPages) {
      const endMsg = document.createElement('div');
      endMsg.className = 'text-xs text-center text-slate-500 py-2';
      endMsg.textContent = 'End of items reached';
      container.appendChild(endMsg);
    }
  }, 500);
}

container.addEventListener('scroll', () => {
  const { scrollTop, clientHeight, scrollHeight } = container;
  if (scrollHeight - scrollTop - clientHeight < 50) {
    loadMoreItems();
  }
});
